   0 &amp; 1 &amp; 0  \cr 

 } } \right],\,{P_6} = \left[ {\matrix{
   0 &amp; 0 &amp; 1  \cr 
   0 &amp; 1 &amp; 0  \cr 
   1 &amp; 0 &amp; 0  \cr 

 } } \right]$$ and $$X = \sum\limits_{k = 1}^6 {{P_k}} \left[ {\matrix{
   2 &amp; 1 &amp; 3  \cr 
   1 &amp; 0 &amp; 2  \cr 
   3 &amp; 2 &amp; 1  \cr 

 } } \right]P_k^T$$<br><br>$$ \because $$ $$P_1^T = {P_1},\,P_2^T = {P_2},\,P_3^T = {P_3},\,P_4^T = {P_5},\,P_5^T = {P_4}$$ and $$P_6^T = {P_6}$$<br><br>and Let $$Q = \left[ {\matrix{
   2 &amp; 1 &amp; 3  \cr 
   1 &amp; 0 &amp; 2  \cr 
   3 &amp; 2 &amp; 1  \cr 

 } } \right]$$<br><br>and $$ \because $$ Q<sup>T</sup> = Q<br><br>Now, <br><br>$$X = ({P_1}QP_1^T) + ({P_2}QP_2^T) + ({P_3}QP_3^T) + ({P_4}QP_4^T) + ({P_5}QP_5^T) + ({P_6}QP_6^T)$$<br><br>So, $${X^T} = {({P_1}QP_1^T)^T} + {({P_2}QP_2^T)^T} + {({P_3}QP_3^T)^T} + {({P_4}QP_4^T)^T} + {({P_5}QP_5^T)^T} + {({P_6}QP_6^T)^T}$$<br><br>= $${P_1}QP_1^T$$ + $${P_2}QP_2^T$$ + $${P_3}QP_3^T$$ + $${P_4}QP_4^T$$ + $${P_5}QP_5^T$$ + $${P_6}QP_6^T$$<br><br>[$$ \because $$ (ABC)<sup>T</sup> = C<sup>T</sup>B<sup>T</sup>A<sup>T</sup> and (A<sup>T</sup>)<sup>T</sup> = A and Q<sup>T</sup> = Q]<br><br>$$ \Rightarrow $$ X<sup>T</sup> = X<br><br>$$ \Rightarrow $$ X is a symmetric matrix.<br><br>The sum of diagonal entries of X = Tr(X)<br><br>$$ = \sum\limits_{i = 1}^6 {{T_r}({P_i}QP_i^T) = \sum\limits_{i = 1}^6 {{T_r}(QP_i^T{P_i})} } $$ [$$ \because $$ T<sub>r</sub>(ABC) = T<sub>r</sub>(BCA)]<br><br>$$ = \sum\limits_{i = 1}^6 {{T_r}(QI)} $$<br><br>[$$ \because $$ P<sub>i</sub>'s are orthogonal matrices]<br><br>$$ = \sum\limits_{i = 1}^6 {{T_r}(Q) = 6{T_r}(Q) = 6 \times 3 = 18} $$<br><br>Now, Let $$R = \left[ {\matrix{
   1  \cr 
   1  \cr 
   1  \cr 

 } } \right]$$, then<br><br>$$XR = \sum\limits_{K = 1}^6 {({P_K}} QP_K^T)R = \sum\limits_{K = 1}^6 {({P_K}QP_K^TR)} $$<br><br>$$ = \sum\limits_{K = 1}^6 {({P_K}QR)} $$ [$$ \because $$ $$P_K^T$$R = R]<br><br>$$ = \sum\limits_{K = 1}^6 {{P_K}\left[ {\matrix{
   6  \cr 
   3  \cr 
   6  \cr 

 } } \right]} $$<br><br>$$ = \sum\limits_{K = 1}^6 {{P_K}\left[ {\matrix{
   6  \cr 
   3  \cr 
   6  \cr 

 } } \right]}  = \left[ {\matrix{
   2 &amp; 2 &amp; 2  \cr 
   2 &amp; 2 &amp; 2  \cr 
   2 &amp; 2 &amp; 2  \cr 

 } } \right]\left[ {\matrix{
   6  \cr 
